mapper.select:
SELECT r.record_id, r.order_no, r.phone_number, c.content, r.send_status, CASE r.send_status WHEN 0 THEN '待发送' WHEN 1 THEN '发送中' WHEN 2 THEN '发送成功' WHEN -1 THEN '发送失败' ELSE '未知' END AS send_status_desc, r.send_time, r.fail_reason, r.create_time, r.pay_amount, r.currency, r.charge_count, r.unit_price, r.me_pay_amount FROM sms_phone_record r LEFT JOIN sms_content c ON r.content_id = c.content_id LEFT JOIN sms_order o ON r.order_no = o.order_no
r.is_deleted = 0
AND r.order_no LIKE CONCAT('%', #{queryParams.orderNo}, '%')
AND o.country_id = #{queryParams.countryId}
AND r.phone_number LIKE CONCAT('%', #{queryParams.phone_number}, '%')
AND r.send_status = #{queryParams.sendStatus}
AND r.create_time >= #{queryParams.startDate}
AND r.create_time <= #{queryParams.endDate}
AND DATE(r.create_time) = #{queryParams.createTime}
AND c.content LIKE CONCAT('%', #{queryParams.content}, '%')
AND r.create_by = #{currentUserId}
ORDER BY r.create_time DESC
